create table promo_usage (
    usage_id       number generated by default as identity not null enable,
    promo_id       varchar2(30 byte),
    invoice_id     varchar2(30 byte),
    customer_id    varchar2(50 byte),
    applied_amount number(12, 2),
    applied_at     date default sysdate,
    applied_by     varchar2(200 byte)
);

alter table promo_usage add primary key ( usage_id )
    using index enable;


